import React from 'react';

interface AppointmentCardProps {
  appointment: any;
  patient: any;
  doctor: any;
  onEdit: () => void;
  onDelete: () => void;
}

const AppointmentCard = ({ appointment, patient, doctor, onEdit, onDelete }: AppointmentCardProps) => (
  <div className="bg-white p-6 rounded-3xl border-l-8 border-amber-400 shadow-sm hover:shadow-md transition-all group relative">
    <div className="flex gap-4">
      <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-2xl group-hover:rotate-12 transition-transform">
        📅
      </div>
      <div>
        <div className="flex items-center gap-3 mb-1">
          <h4 className="text-xl font-bold text-slate-800">
            {patient ? `${patient.first_name} ${patient.last_name}` : 'Unknown Patient'}
          </h4>
          <span className="bg-amber-50 text-amber-700 text-[10px] px-2.5 py-1 rounded-full font-bold uppercase border border-amber-100">
            {appointment.status}
          </span>
        </div>
        <p className="text-amber-600 font-medium text-sm">
          with Dr. {doctor?.last_name || 'Doctor'}
        </p>
        <p className="text-slate-400 text-xs mt-2 font-mono flex items-center gap-1">
          <span>📅 Schedule:</span> {appointment.appointment_date}
        </p>
      </div>
    </div>

    {/* Hover Actions */}
    <div className="absolute top-4 right-4 flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity">
      <button 
        onClick={onEdit} 
        className="text-slate-400 hover:text-amber-600 font-bold text-xs p-1"
      >
        EDIT
      </button>
      <button 
        onClick={onDelete} 
        className="text-slate-400 hover:text-red-500 font-bold text-xs p-1"
      >
        DELETE
      </button>
    </div>
  </div>
);

export default AppointmentCard;
